class Solution:
    def squareIsWhite(self, coordinates):
        white_a = {'a1': False, 'b1': True}
        col = ord(coordinates[0]) - ord('a')
        row = ord(coordinates[1]) - ord('1')
        # a1 (col0,row0) is black; toggle by each step
        black = True
        for _ in range(col):
            black = not black
        for _ in range(row):
            black = not black
        return not black

